function seedPlanosContas() {
  const existing = DB.get('planos_contas') || [];
  let changed = false;
  PLANOS_SEED.forEach(seed => {
    const idx = existing.findIndex(p => String(p.id) === seed.id || p.nome === seed.nome || p.nome === seed.id);
    if (idx === -1) {
      // Plano não existe — adicionar
      existing.push({
        id: seed.id, nome: seed.nome, contas: seed.contas,
        data: seed.data, planoPadrao: seed.id,
        stats: {
          analiticas: seed.contas.filter(c => !c.tipo || c.tipo === '').length,
          sinteticas: seed.contas.filter(c => c.tipo === 'T').length,
          consolidadas: seed.contas.filter(c => c.tipo === 'C').length,
        }
      });
      changed = true;
    } else if (!existing[idx].contas || existing[idx].contas.length === 0) {
      // Plano existe mas com 0 contas (importação antiga/corrompida) — substituir
      existing[idx] = {
        id: seed.id, nome: seed.nome, contas: seed.contas,
        data: seed.data, planoPadrao: seed.id,
        stats: {
          analiticas: seed.contas.filter(c => !c.tipo || c.tipo === '').length,
          sinteticas: seed.contas.filter(c => c.tipo === 'T').length,
          consolidadas: seed.contas.filter(c => c.tipo === 'C').length,
        }
      };
      changed = true;
    }
  });
  if (changed) {
    DB.set('planos_contas', existing);
    console.log('[Seed] Planos de contas SCI carregados:', existing.length, 'planos');
  }
}
